// Lê uma conversa de WhatsApp a partir de um arquivo: .txt direto ou .zip (export com mídia)
async function lerArquivoConversa(file: File): Promise<string> {
  if (/\.zip$/i.test(file.name)) {
    const zip = await JSZip.loadAsync(file);
    const nomes = Object.keys(zip.files).filter(n => !zip.files[n].dir);
    const alvo = nomes.find(n => /_chat\.txt$/i.test(n)) || nomes.find(n => /\.txt$/i.test(n));
    if (!alvo) throw new Error("Nenhum arquivo de conversa (.txt) encontrado no zip.");
    return await zip.files[alvo].async("string");
  }
  return await file.text();
}

