function localToDb(l) {
  return {
    nome: l.nome||"", telefone: l.telefone||"", origem: l.origem||"",
    finalidade: l.finalidade||"", tipo: l.tipo||"", segmento: l.segmento||"",
    situacao: l.situacao||"", empreendimento: l.empreendimento||"", bairro: l.bairro||"",
    preco_min: l.precoMin ? Number(l.precoMin) : null,
    preco_max: l.precoMax ? Number(l.precoMax) : null,
    quartos: l.quartos ? Number(l.quartos) : null,
    vagas: l.vagas ? Number(l.vagas) : null,
    anotacoes: l.anotacoes||"", stage: l.stage||"novo",
    proxima_acao: l.proximaAcao||"",
    proxima_acao_data: l.proximaAcaoData||null,
    ultimo_contato: l.ultimoContato||null,
    criado_em: l.criadoEm||null,
    historico: l.historico||[],
    apresentacao_id: l.apresentacaoId||null,
    book_url: l.bookUrl||null,
  };
}

function dbToLocal(d) {
  return {
    id: d.id, dbId: d.id,
    nome: d.nome||"", telefone: d.telefone||"", origem: d.origem||"",
    finalidade: d.finalidade||"", tipo: d.tipo||"", segmento: d.segmento||"",
    situacao: d.situacao||"", empreendimento: d.empreendimento||"", bairro: d.bairro||"",
    precoMin: d.preco_min||"", precoMax: d.preco_max||"",
    quartos: d.quartos||"", vagas: d.vagas||"",
    anotacoes: d.anotacoes||"", stage: d.stage||"novo",
    proximaAcao: d.proxima_acao||"", proximaAcaoData: d.proxima_acao_data||"",
    ultimoContato: d.ultimo_contato||"", criadoEm: d.criado_em||"",
    historico: d.historico||[],
    apresentacaoId: d.apresentacao_id||"",
    bookUrl: d.book_url||"",
  };
}

const db = {
  async getAll() {
    try {
      const r = await supaFetch("leads?order=created_at.desc");
      if (!r.ok) { console.error("getAll error:", await r.text()); return []; }
      const data = await r.json();
      return Array.isArray(data) ? data.map(dbToLocal) : [];
    } catch(e) { console.error("getAll exception:", e); return []; }
  },
  async insert(lead) {
    try {
      const body = localToDb(lead);
      const r = await supaFetch("leads", { method: "POST", body: JSON.stringify(body) });
      const text = await r.text();
      if (!r.ok) { alert("Erro ao salvar:\n" + text); return null; }
      const data = JSON.parse(text);
      return data[0] ? dbToLocal(data[0]) : null;
    } catch(e) { alert("Erro de conexão: " + e.message); return null; }
  },
  async update(lead) {
    try {
      const r = await supaFetch(`leads?id=eq.${lead.dbId}`, { method: "PATCH", body: JSON.stringify(localToDb(lead)) });
      if (!r.ok) { console.error("update error:", await r.text()); }
    } catch(e) { console.error("update exception:", e); }
  },
  async remove(dbId) {
    try {
      await supaFetch(`leads?id=eq.${dbId}`, { method: "DELETE" });
    } catch(e) { console.error("delete exception:", e); }
  },
};

