const diasSem=(d:string)=>!d?999:Math.floor((new Date().getTime()-new Date(d+"T00:00:00").getTime())/86400000);
const fmtR$=(v: any): string =>v?"R$ "+Number(v).toLocaleString("pt-BR"):"";
const fmtData=(d: string): string =>d?new Date(d+"T00:00:00").toLocaleDateString("pt-BR"):"";
const calcTemp=(l: any): string =>{
  const d=diasSem(l.ultimoContato);
  if(["visita","proposta"].includes(l.stage)&&d<4) return "quente";
  if(d>10||l.stage==="parou") return "frio";
  return "morno";
};
