function useIsMobile(){
  const [m,setM]=useState(typeof window!=="undefined"&&window.innerWidth<768);
  useEffect(()=>{const h=()=>setM(window.innerWidth<768);window.addEventListener("resize",h);return()=>window.removeEventListener("resize",h);},[]);
  return m;
}

const SENHA="t3teiA";
function LoginGate({children}){
  const [ok,setOk]=React.useState(()=>localStorage.getItem("crm_auth")==="1");
  const [val,setVal]=React.useState("");
  const [erro,setErro]=React.useState(false);
  if(ok)return children;
  const tentar=()=>{
    if(val===SENHA){localStorage.setItem("crm_auth","1");setOk(true);}
    else{setErro(true);setVal("");}
  };
  return(
    <div style={{display:"flex",alignItems:"center",justifyContent:"center",minHeight:"100vh",background:C.bg}}>
      <div style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:12,padding:"2rem",width:300,textAlign:"center"}}>
        <div style={{fontSize:18,fontWeight:700,color:C.brownL,marginBottom:4}}>Arimateia Imóveis</div>
        <div style={{fontSize:12,color:C.muted,marginBottom:24}}>CRM</div>
        <input
          type="password" value={val} onChange={e=>{setVal(e.target.value);setErro(false);}}
          onKeyDown={e=>e.key==="Enter"&&tentar()}
          placeholder="Senha"
          autoFocus
          style={{width:"100%",background:C.card,border:`1px solid ${erro?C.neg:C.border}`,borderRadius:6,padding:"10px 12px",color:C.text,fontSize:14,marginBottom:8,boxSizing:"border-box"}}
        />
        {erro&&<div style={{fontSize:12,color:C.neg,marginBottom:8}}>Senha incorreta.</div>}
        <button onClick={tentar} style={{width:"100%",background:C.brown,color:"#fff",border:"none",borderRadius:6,padding:"10px",fontSize:14,fontWeight:600,cursor:"pointer"}}>Entrar</button>
      </div>
    </div>
  );
}

