  const curtidos=imoveis.filter(d=>votos&&votos[d.idx]==="like");
  const nao=imoveis.filter(d=>votos&&votos[d.idx]==="dislike");
  const semVoto=imoveis.filter(d=>!votos||(votos[d.idx]!=="like"&&votos[d.idx]!=="dislike"));

