const TESES_BANCO = [
  "O comprador ansioso (decide a maior compra da vida com menos pesquisa do que faz pra trocar de celular)",
  "A dívida oculta (o que o anúncio não mostra: IPTU, condomínio, penhora, matrícula)",
  "Corretor ≠ consultor (um entrega a chave, o outro te protege da compra errada)",
  "O bairro subestimado (por que o Ipiranga / regiões em valorização)",
  "O erro do investidor (o que ninguém calcula antes de comprar pra alugar/Airbnb)",
];
const OBJECOES_BANCO = [
  "tá caro",
  "vou esperar o juro baixar",
  "e se desvalorizar",
  "prefiro alugar",
  "melhor esperar as eleições",
];
const MODOS_BANCO = [
  {id:"crm", label:"🎯 CRM sugere"},
  {id:"tese", label:"Tese fixa"},
  {id:"objecao", label:"Quebra de objeção"},
  {id:"noticia", label:"Reagir a notícia"},
  {id:"livre", label:"Tema livre"},
];

const CRIATIVO_KEY="criativo_work_v1";
const MODEL_TEXTO="claude-sonnet-4-6"; // geração de conteúdo: Sonnet escreve muito melhor que Haiku

// sugere um tema/nome curto para a peça (palavra-chave SEO ou o gancho)
function sugerirTema(peca:string,gancho:string):string{
  const seo=peca.match(/palavra-chave SEO:\s*["“]?([^"”\n]+)["”]?/i);
  if(seo&&seo[1].trim()) return seo[1].trim().slice(0,60);
  return (gancho||"").replace(/[{}\[\]\/*_]/g,"").trim().slice(0,60);
}

function GeradorConteudo({setTab}:{setTab:(t:string)=>void}){
  const [modo,setModo]=React.useState("objecao");
  const [contexto,setContexto]=React.useState(OBJECOES_BANCO[0]);
  const [step,setStep]=React.useState<"input"|"chat"|"peca">("input");
  const [chat,setChat]=React.useState<{role:string,content:string}[]>([]);
  const [chatInput,setChatInput]=React.useState("");
  const [peca,setPeca]=React.useState("");
  const [load,setLoad]=React.useState(false);
  const [instrucao,setInstrucao]=React.useState("");
  const [rascunhos,setRascunhos]=React.useState<any[]>([]);
  const [showSalvar,setShowSalvar]=React.useState(false);
  const [saveTema,setSaveTema]=React.useState("");
  const [saveData,setSaveData]=React.useState("");
  const [saveStatus,setSaveStatus]=React.useState("rascunho");
  const [saving,setSaving]=React.useState(false);
  const [editandoId,setEditandoId]=React.useState<string|null>(null);
  const [toast,setToast]=React.useState("");
  const [crmResumo,setCrmResumo]=React.useState("");
  const [showEditor,setShowEditor]=React.useState(false);
  const [editorSlides,setEditorSlides]=React.useState<any[]|null>(null);

  // restaura trabalho em andamento (sobrevive a trocar de aba / recarregar)
  React.useEffect(()=>{
    carregarRascunhos();
    try{
      const raw=localStorage.getItem(CRIATIVO_KEY);
      if(raw){
        const w=JSON.parse(raw);
        if(w.peca||w.chat?.length){setModo(w.modo||"objecao");setContexto(w.contexto||"");setPeca(w.peca||"");setStep(w.step||(w.peca?"peca":"chat"));setEditorSlides(w.editorSlides||null);setSaveTema(w.saveTema||"");setChat(w.chat||[]);}
      }
    }catch{}
  },[]);

  // persiste o trabalho em andamento
  React.useEffect(()=>{
    try{
      if(peca||chat.length) localStorage.setItem(CRIATIVO_KEY,JSON.stringify({peca,step,modo,contexto,editorSlides,saveTema,chat}));
    }catch{}
  },[peca,step,modo,contexto,editorSlides,saveTema,chat]);

  const carregarRascunhos=async()=>{
    try{
      const r=await supaFetch("conteudos?select=id,tema,modo,status,data_agendada,criado_em&order=criado_em.desc&limit=30");
      if(r.ok)setRascunhos(await r.json());
    }catch{}
  };

  const salvarRascunho=async()=>{
    if(!saveTema.trim())return;
    setSaving(true);
    try{
      const body={tema:saveTema,modo,contexto,peca,status:saveStatus,data_agendada:saveData||null};
      if(editandoId){
        await supaFetch(`conteudos?id=eq.${editandoId}`,{method:"PATCH",body:JSON.stringify(body)});
      } else {
        await supaFetch("conteudos",{method:"POST",body:JSON.stringify(body)});
      }
      setShowSalvar(false);setSaveData("");setSaveStatus("rascunho");setEditandoId(null);
      carregarRascunhos();
      setToast(editandoId?"Rascunho atualizado ✓":"Salvo nos rascunhos ✓");
      setTimeout(()=>setToast(""),3000);
    }catch(e:any){alert("Erro ao salvar: "+e.message);}
    setSaving(false);
  };

  const carregarConteudo=async(id:string)=>{
    try{
      const r=await supaFetch(`conteudos?id=eq.${id}&select=*`);
      if(!r.ok)return;
      const [c]=await r.json();
      setModo(c.modo||"livre");setContexto(c.contexto||"");setPeca(c.peca||"");
      setStep("peca");setEditandoId(id);setSaveTema(c.tema||"");setSaveData(c.data_agendada||"");setSaveStatus(c.status||"rascunho");setEditorSlides(null);
    }catch{}
  };

  const excluirConteudo=async(id:string)=>{
    if(!window.confirm("Excluir este rascunho?"))return;
    await supaFetch(`conteudos?id=eq.${id}`,{method:"DELETE"});
    carregarRascunhos();
  };

  const mudarModo=async(m:string)=>{
    setModo(m);
    setContexto(m==="tese"?TESES_BANCO[0]:m==="objecao"?OBJECOES_BANCO[0]:"");
    setStep("input");setChat([]);setPeca("");setCrmResumo("");
    if(m==="crm"){
      try{
        const r=await supaFetch("leads?select=stage,finalidade,tipo,segmento,bairro,precoMin,precoMax,anotacoes,ultimoContato&limit=200");
        if(!r.ok)return;
        const leads:any[]=await r.json();
        const ativos=leads.filter(l=>!["fechado","perdido"].includes(l.stage));
        const stageCount:Record<string,number>={};
        ativos.forEach(l=>{stageCount[l.stage]=(stageCount[l.stage]||0)+1;});
        const bairros:Record<string,number>={};
        ativos.forEach(l=>{if(l.bairro){bairros[l.bairro]=(bairros[l.bairro]||0)+1;}});
        const topBairros=Object.entries(bairros).sort((a,b)=>b[1]-a[1]).slice(0,3).map(([b,n])=>`${b} (${n})`).join(", ");
        const segmentos:Record<string,number>={};
        ativos.forEach(l=>{if(l.segmento){segmentos[l.segmento]=(segmentos[l.segmento]||0)+1;}});
        const topSeg=Object.entries(segmentos).sort((a,b)=>b[1]-a[1]).slice(0,2).map(([s,n])=>`${s} (${n})`).join(", ");
        const diasSem=(d:string)=>d?Math.floor((Date.now()-new Date(d).getTime())/86400000):99;
        const quentes=ativos.filter(l=>["visita","proposta"].includes(l.stage)&&diasSem(l.ultimoContato)<4).length;
        const esfriando=ativos.filter(l=>diasSem(l.ultimoContato)>=5&&diasSem(l.ultimoContato)<=10).length;
        const estagios=Object.entries(stageCount).map(([s,n])=>`${s}: ${n}`).join(", ");
        const resumo=`Funil atual (${ativos.length} leads ativos): ${estagios}. Bairros mais buscados: ${topBairros||"variado"}. Segmentos dominantes: ${topSeg||"variado"}. Leads quentes (visita/proposta, <4 dias): ${quentes}. Leads esfriando (5-10 dias sem contato): ${esfriando}.`;
        setCrmResumo(resumo);
        setContexto(resumo);
      }catch{}
    }
  };

  const callProxy=async(prompt:string,maxTokens:number)=>{
    const r=await fetch("/api/claude-proxy",{method:"POST",headers:{"Content-Type":"application/json"},
      body:JSON.stringify({system:SYSTEM_ARIMATEIA,prompt,maxTokens,model:MODEL_TEXTO})});
    if(!r.ok)throw new Error("Erro "+r.status);
    const data=await r.json();
    if(data.error)throw new Error(data.error.message);
    return data.text||"";
  };
  // conversa multi-turno (ideação) — Sonnet acha o ângulo antes de gerar
  const callChat=async(msgs:{role:string,content:string}[],maxTokens:number)=>{
    const r=await fetch("/api/claude-proxy",{method:"POST",headers:{"Content-Type":"application/json"},
      body:JSON.stringify({system:SYSTEM_ARIMATEIA,messages:msgs,maxTokens,model:MODEL_TEXTO})});
    if(!r.ok)throw new Error("Erro "+r.status);
    const data=await r.json();
    if(data.error)throw new Error(data.error.message);
    return data.text||"";
  };

  // semente da conversa: modo + contexto viram a 1ª fala; a IA responde com perguntas afiadas
  const seedConversa=()=>{
    const mLabel=MODOS_BANCO.find(m=>m.id===modo)?.label||modo;
    if(modo==="crm") return `Modo: ${mLabel}. Aqui está o funil de vendas atual:\n\n${contexto}\n\nOlha esse funil e me ajuda a achar o ângulo de conteúdo mais estratégico pro momento. Me faz as perguntas que precisar pra afiar antes de gerar.`;
    return `Modo: ${mLabel}\nContexto: ${contexto}\n\nMe ajuda a achar o ângulo real disso antes de escrever o carrossel. Pode me perguntar o que precisar.`;
  };

  const iniciarConversa=async()=>{
    if(!contexto.trim())return;
    setLoad(true);setStep("chat");
    try{
      const msgs=[{role:"user",content:seedConversa()}];
      const reply=await callChat(msgs,800);
      setChat([...msgs,{role:"assistant",content:reply}]);
    }catch(e:any){alert("Erro: "+e.message);setStep("input");}
    setLoad(false);
  };

  const enviarMsg=async()=>{
    const text=chatInput.trim();if(!text||load)return;
    const msgs=[...chat,{role:"user",content:text}];
    setChat(msgs);setChatInput("");setLoad(true);
    try{
      const reply=await callChat(msgs,800);
      setChat([...msgs,{role:"assistant",content:reply}]);
    }catch(e:any){setChat([...msgs,{role:"assistant",content:"⚠ "+e.message}]);}
    setLoad(false);
  };

  const gerarDaConversa=async()=>{
    if(!chat.length||load)return;
    setLoad(true);
    try{
      const msgs=[...chat,{role:"user",content:`Agora gere a PEÇA completa no formato CARROSSEL, usando os detalhes reais e o ângulo que a gente afinou aqui — nada de genérico. Siga exatamente o formato de saída (cada "Slide N — PAPEL · fundo" em nova linha, gatilho de interação no meio, gancho de continuidade no fim, LEGENDA e exatamente 5 hashtags). Capa que JÁ abre uma lacuna. Não force subtítulo em todo slide.`}];
      const txt=await callChat(msgs,2800);
      setPeca(txt);setStep("peca");setEditorSlides(null);
      setSaveTema(prev=>prev||sugerirTema(txt,chat.find(m=>m.role==="user")?.content||""));
    }catch(e:any){alert("Erro: "+e.message);}
    setLoad(false);
  };

  const refinar=async()=>{
    if(!instrucao.trim()||!peca)return;
    setLoad(true);
    try{
      const txt=await callProxy(`Você está refinando um carrossel de Instagram já pronto.\n\nREGRA ABSOLUTA: devolva SEMPRE a peça completa do início ao fim, com todos os slides, legenda e hashtags — nunca só o trecho alterado. Altere APENAS o que a instrução pede; mantenha tudo o mais intacto, incluindo estrutura, marcações ({} [] / ↳) e número de slides.\n\nPEÇA ATUAL:\n${peca}\n\nINSTRUÇÃO: ${instrucao}`,2800);
      setPeca(txt);setInstrucao("");setEditorSlides(null);
    }catch(e:any){alert("Erro: "+e.message);}
    setLoad(false);
  };

  const resetar=()=>{setStep("input");setChat([]);setChatInput("");setPeca("");setInstrucao("");setEditorSlides(null);setSaveTema("");try{localStorage.removeItem(CRIATIVO_KEY);}catch{}};

  const sugestoes=modo==="tese"?TESES_BANCO:modo==="objecao"?OBJECOES_BANCO:[];

  return(
    <div style={{padding:"20px 24px",maxWidth:760}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
        <div style={{fontSize:10,fontWeight:700,letterSpacing:2,color:C.brownL,textTransform:"uppercase" as const}}>✦ Gerador de Conteúdo · Instagram</div>
        <button onClick={()=>setTab("kanban")} style={{...btnS(),fontSize:12}}>← Leads</button>
      </div>

      {toast&&(
        <div style={{background:C.pos+"22",border:`1px solid ${C.pos}`,color:C.pos,borderRadius:8,padding:"10px 16px",marginBottom:16,fontSize:13,fontWeight:500,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <span>{toast}</span>
          <button onClick={()=>{setStep("input");setToast("");}} style={{...btnS(C.pos+"22",C.pos,C.pos),fontSize:11,padding:"4px 10px"}}>Ver rascunhos</button>
        </div>
      )}

      {/* RASCUNHOS SALVOS */}
      {rascunhos.length>0&&step==="input"&&(
        <div style={{marginBottom:24}}>
          <div style={{fontSize:10,color:C.muted,textTransform:"uppercase" as const,letterSpacing:.5,marginBottom:10}}>Rascunhos salvos</div>
          <div style={{display:"flex",flexDirection:"column" as const,gap:6}}>
            {rascunhos.map(r=>(
              <div key={r.id} style={{background:C.card,border:`1px solid ${C.border}`,borderRadius:8,padding:"10px 14px",display:"flex",alignItems:"center",gap:10}}>
                <div style={{flex:1,cursor:"pointer"}} onClick={()=>carregarConteudo(r.id)}>
                  <span style={{fontSize:13,color:C.text,fontWeight:500}}>{r.tema}</span>
                  <span style={{fontSize:11,color:C.muted,marginLeft:10}}>{r.modo}</span>
                  {r.data_agendada&&<span style={{fontSize:11,color:C.brownL,marginLeft:10}}>📅 {r.data_agendada}</span>}
                  <span style={{fontSize:11,color:r.status==="agendado"?C.brownL:r.status==="publicado"?C.pos:C.muted,marginLeft:10,textTransform:"uppercase" as const,letterSpacing:.5}}>{r.status}</span>
                </div>
                <button onClick={()=>excluirConteudo(r.id)} style={{...btnS(),fontSize:11,padding:"4px 8px",color:C.neg}}>✕</button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* STEP 1 — INPUT */}
      {step==="input"&&(
        <div>
          {/* modo */}
          <div style={{marginBottom:18}}>
            <div style={{fontSize:10,color:C.muted,textTransform:"uppercase" as const,letterSpacing:.5,marginBottom:8}}>Modo</div>
            <div style={{display:"flex",gap:6,flexWrap:"wrap" as const}}>
              {MODOS_BANCO.map(m=>(
                <button key={m.id} onClick={()=>mudarModo(m.id)}
                  style={{...btnS(modo===m.id?C.brown:"transparent",modo===m.id?C.text:C.muted,modo===m.id?C.brown:C.border),fontSize:12,padding:"7px 16px"}}>
                  {m.label}
                </button>
              ))}
            </div>
          </div>

          {/* modo CRM — resumo do funil */}
          {modo==="crm"&&(
            <div style={{marginBottom:18}}>
              {crmResumo
                ? <div style={{background:C.card,border:`1px solid ${C.brown}`,borderRadius:8,padding:"12px 14px"}}>
                    <div style={{fontSize:10,color:C.brownL,textTransform:"uppercase" as const,letterSpacing:.5,marginBottom:8}}>Funil analisado</div>
                    <div style={{fontSize:12,color:C.text,lineHeight:1.6}}>{crmResumo}</div>
                  </div>
                : <div style={{fontSize:12,color:C.muted}}>Analisando funil...</div>
              }
            </div>
          )}

          {/* sugestões rápidas */}
          {sugestoes.length>0&&(
            <div style={{marginBottom:12}}>
              <div style={{fontSize:10,color:C.muted,textTransform:"uppercase" as const,letterSpacing:.5,marginBottom:8}}>Sugestões</div>
              <div style={{display:"flex",flexDirection:"column" as const,gap:4}}>
                {sugestoes.map(o=>(
                  <button key={o} onClick={()=>setContexto(o)}
                    style={{...btnS(contexto===o?C.card2:"transparent",contexto===o?C.brownL:C.muted,contexto===o?C.brown:C.border),textAlign:"left" as const,fontSize:12,padding:"7px 12px"}}>
                    {o}
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* contexto livre — escondido no modo CRM */}
          {modo!=="crm"&&<div style={{marginBottom:18}}>
            <div style={{fontSize:10,color:C.muted,textTransform:"uppercase" as const,letterSpacing:.5,marginBottom:8}}>
              {modo==="tese"?"Tese":modo==="objecao"?"Objeção":modo==="noticia"?"Manchete / notícia colada":"Tema"}
            </div>
            <textarea value={contexto} onChange={e=>setContexto(e.target.value)}
              rows={modo==="noticia"?5:2}
              placeholder={modo==="noticia"?"Cole a manchete ou o texto da notícia...":modo==="livre"?"Ex: dívida de condomínio oculta em imóveis do Ipiranga":"ou escreva sua própria..."}
              style={{...inp,resize:"vertical" as const}}/>
          </div>}

          <button onClick={iniciarConversa} disabled={load||!contexto.trim()}
            style={{...btnS(C.brown,C.text,C.brown),padding:"10px 24px",fontSize:13,opacity:load||!contexto.trim()?0.5:1}}>
            {load?"Pensando...":"✦ Conversar e achar o ângulo →"}
          </button>
          <div style={{fontSize:11,color:C.muted,marginTop:8,lineHeight:1.5}}>A IA te faz 2-3 perguntas afiadas pra achar o ângulo real antes de escrever. Quando estiver bom, é só clicar em gerar.</div>
        </div>
      )}

      {/* STEP 2 — CONVERSA (ideação: acha o ângulo antes de gerar) */}
      {step==="chat"&&(
        <div>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
            <div style={{fontSize:13,fontWeight:600,color:C.text}}>Achando o ângulo</div>
            <button onClick={resetar} style={{...btnS(),fontSize:12}}>← Voltar</button>
          </div>

          <div style={{display:"flex",flexDirection:"column" as const,gap:10,marginBottom:14}}>
            {chat.slice(1).map((m,i)=>(
              <div key={i} style={{display:"flex",justifyContent:m.role==="user"?"flex-end":"flex-start"}}>
                <div style={{maxWidth:"82%",background:m.role==="user"?C.brown:C.card,color:m.role==="user"?C.text:C.text,
                  border:`1px solid ${m.role==="user"?C.brown:C.border}`,borderRadius:m.role==="user"?"12px 12px 3px 12px":"12px 12px 12px 3px",
                  padding:"10px 14px",fontSize:13,lineHeight:1.55,whiteSpace:"pre-wrap" as const}}>{m.content}</div>
              </div>
            ))}
            {load&&<div style={{fontSize:12,color:C.muted,fontStyle:"italic" as const}}>pensando…</div>}
          </div>

          <div style={{display:"flex",gap:8,marginBottom:12}}>
            <textarea value={chatInput} onChange={e=>setChatInput(e.target.value)} rows={2}
              onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();enviarMsg();}}}
              placeholder="responde a IA… (ou escreve um detalhe real: número, bairro, caso de cliente)"
              style={{...inp,flex:1,resize:"vertical" as const,fontSize:13}}/>
            <button onClick={enviarMsg} disabled={load||!chatInput.trim()}
              style={{...btnS(C.card2,C.text,C.border),fontSize:13,padding:"0 16px",opacity:load||!chatInput.trim()?0.5:1}}>➤</button>
          </div>

          <button onClick={gerarDaConversa} disabled={load||chat.length<2}
            style={{...btnS(C.brown,C.text,C.brown),padding:"11px 24px",fontSize:13,width:"100%",fontWeight:700,opacity:load||chat.length<2?0.5:1}}>
            {load?"Gerando carrossel...":"✦ Gerar carrossel → Editor"}
          </button>
        </div>
      )}

      {showEditor&&<EditorVisual peca={peca} initialSlides={editorSlides} onChange={setEditorSlides} onClose={()=>setShowEditor(false)}/>}

      {/* STEP 3 — PEÇA COMPLETA */}
      {step==="peca"&&(
        <div>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16,flexWrap:"wrap" as const,gap:8}}>
            <div style={{fontSize:13,fontWeight:600,color:C.text}}>Peça gerada</div>
            <div style={{display:"flex",gap:8,flexWrap:"wrap" as const}}>
              {chat.length>0&&<button onClick={()=>{setStep("chat");setPeca("");}} style={{...btnS(),fontSize:12}}>← Conversa</button>}
              <button onClick={resetar} style={{...btnS(),fontSize:12}}>Nova peça</button>
              <button onClick={()=>navigator.clipboard.writeText(peca)} style={{...btnS(C.card2,C.pos,C.pos+"44"),fontSize:12,padding:"6px 14px"}}>Copiar tudo</button>
              <button onClick={()=>setShowSalvar(v=>!v)} style={{...btnS(C.brown,C.text,C.brown),fontSize:12,padding:"6px 14px"}}>
                {editandoId?"↺ Atualizar rascunho":"✦ Salvar"}
              </button>
              <button onClick={()=>setShowEditor(true)} style={{...btnS("#4a3728",C.brownL,"#4a3728"),fontSize:12,padding:"6px 14px",fontWeight:700}}>
                → Criar visual
              </button>
            </div>
          </div>

          {/* edição manual */}
          <textarea value={peca} onChange={e=>setPeca(e.target.value)} rows={28}
            style={{...inp,resize:"vertical" as const,fontFamily:"inherit",fontSize:13,lineHeight:1.75,marginBottom:16}}/>

          {/* formulário salvar */}
          {showSalvar&&(
            <div style={{background:C.card,border:`1px solid ${C.brown}`,borderRadius:8,padding:"14px 16px",marginBottom:16}}>
              <div style={{fontSize:10,color:C.brownL,textTransform:"uppercase" as const,letterSpacing:.5,marginBottom:12}}>Salvar conteúdo</div>
              <div style={{display:"flex",flexDirection:"column" as const,gap:10}}>
                <input value={saveTema} onChange={e=>setSaveTema(e.target.value)} placeholder="Tema (ex: tá caro — ciclo de mercado)" style={{...inp,fontSize:13}}/>
                <div style={{display:"flex",gap:10}}>
                  <div style={{flex:1}}>
                    <div style={{fontSize:10,color:C.muted,marginBottom:6}}>Status</div>
                    <div style={{display:"flex",gap:6}}>
                      {["rascunho","agendado","publicado"].map(s=>(
                        <button key={s} onClick={()=>setSaveStatus(s)}
                          style={{...btnS(saveStatus===s?C.brown:"transparent",saveStatus===s?C.text:C.muted,saveStatus===s?C.brown:C.border),fontSize:11,padding:"5px 10px",textTransform:"capitalize" as const}}>
                          {s}
                        </button>
                      ))}
                    </div>
                  </div>
                  {saveStatus==="agendado"&&(
                    <div>
                      <div style={{fontSize:10,color:C.muted,marginBottom:6}}>Data</div>
                      <input type="date" value={saveData} onChange={e=>setSaveData(e.target.value)} style={{...inp,fontSize:12,padding:"5px 10px"}}/>
                    </div>
                  )}
                </div>
                <div style={{display:"flex",gap:8}}>
                  <button onClick={salvarRascunho} disabled={saving||!saveTema.trim()}
                    style={{...btnS(C.brown,C.text,C.brown),padding:"8px 20px",fontSize:12,opacity:saving||!saveTema.trim()?0.5:1}}>
                    {saving?"Salvando...":editandoId?"Atualizar":"Salvar"}
                  </button>
                  <button onClick={()=>setShowSalvar(false)} style={{...btnS(),fontSize:12}}>Cancelar</button>
                </div>
              </div>
            </div>
          )}

          {/* refinamento por IA */}
          <div style={{background:C.card,border:`1px solid ${C.border}`,borderRadius:8,padding:"14px 16px"}}>
            <div style={{fontSize:10,color:C.muted,textTransform:"uppercase" as const,letterSpacing:.5,marginBottom:10}}>Refinar com IA</div>
            <div style={{display:"flex",gap:8}}>
              <input value={instrucao} onChange={e=>setInstrucao(e.target.value)}
                onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey&&instrucao.trim()){e.preventDefault();refinar();}}}
                placeholder='Ex: "deixa o slide 2 mais curto" · "troca o gancho final" · "remove a lista do slide 3"'
                style={{...inp,flex:1,padding:"8px 12px",fontSize:12}}/>
              <button onClick={refinar} disabled={load||!instrucao.trim()}
                style={{...btnS(C.brown,C.text,C.brown),padding:"8px 16px",fontSize:12,opacity:load||!instrucao.trim()?0.5:1,whiteSpace:"nowrap" as const}}>
                {load?"...":"✦ Aplicar"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function Overlay({children,onClose}){
  return(
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.75)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:200,padding:16,backdropFilter:"blur(6px)"}} onClick={onClose}>
      <div style={{background:"#141414",border:`1px solid #2E2E2E`,borderRadius:12,width:"100%",maxWidth:600,maxHeight:"92vh",overflowY:"auto",display:"flex",flexDirection:"column"}} onClick={e=>e.stopPropagation()}>
        <div style={{position:"sticky",top:0,background:"#141414",borderBottom:`1px solid #1e1e1e`,padding:"10px 16px",display:"flex",alignItems:"center",zIndex:10,borderRadius:"12px 12px 0 0"}}>
          <button onClick={onClose} style={{background:"none",border:"none",color:C.muted,fontSize:13,cursor:"pointer",display:"flex",alignItems:"center",gap:6,padding:0,fontFamily:"inherit"}}>
            ← Voltar
          </button>
        </div>
        <div style={{padding:"18px 24px 24px"}}>{children}</div>
      </div>
    </div>
  );
}
function MT({children}){return <div style={{fontSize:16,fontWeight:700,marginBottom:16,color:C.text}}>{children}</div>;}
function Fg({label,children,style={}}){return <div style={{display:"flex",flexDirection:"column",gap:4,...style}}><label style={{fontSize:11,color:C.muted,textTransform:"uppercase",letterSpacing:0.4}}>{label}</label>{children}</div>;}
function Tag({children,color,bg}){return <span style={{background:bg||"transparent",color,border:`1px solid ${color}33`,borderRadius:4,padding:"2px 8px",fontSize:11,fontWeight:500}}>{children}</span>;}
